/// <summary>
/// Extension of the <c>SalesAgreementListPage</c> datasource <c>SalesAgreementHeader</c> for the ETGSPAIN model.
/// </summary>
[ExtensionOf(FormStr(SalesAgreementListPage))]
final class SalesAgreementListPageETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show or hide features in Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINPurchInvoiceType)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINPurchExecutionFromDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINPurchAgreementType)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINPurchCountryRegionIdOrigin)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINAgreementOperationId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINPurchHasAgreementQuotas)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINPurchExecutionDueDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, SalesAgreementHeader_ETGSPAINPurchPlateDaysNumber)).visible(currentCompanyIsSpanishCompany);

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        AgreementHeaderDefault_DS.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(true);
    }

    this.design().controlName(formControlStr(SalesAgreementListPage, BtnProformaConfirmation)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, ProfomaRpt)).visible(!currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreementListPage, ButtonConfirmationETG)).visible(!currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreementListPage, BtnConfirmation)).visible(currentCompanyIsSpanishCompany);
}
